  %ret = fptosi <2 x float> %val to <2 x i32>
  ret <2 x i32> %ret
}

define i32 @fptosi_nonnorm_fmul(float %x) {
  %sel = fmul float %x, 0.000000e+00
  %ret = fptosi float %sel to i32
  ret i32 %ret
}

define i32 @fptosi_select(i1 %cond) {
